import{o as n,c as s,a}from"./app.a612cc0f.js";const p='{"title":"uni 开发差异","description":"","frontmatter":{},"headers":[{"level":2,"title":"iconfont 阿里字体图标","slug":"iconfont-阿里字体图标"},{"level":2,"title":"easycom 引入组件库","slug":"easycom-引入组件库"},{"level":2,"title":"传参","slug":"传参"}],"relativePath":"qv/uni.md","lastUpdated":1622976166491}',t={},o=[a('<h1 id="uni-开发差异"><a class="header-anchor" href="#uni-开发差异" aria-hidden="true">#</a> uni 开发差异</h1><ul><li><a href="https://github.com/dcloudio/uni-app/issues" target="_blank" rel="noopener noreferrer">uni-app</a></li></ul><h2 id="iconfont-阿里字体图标"><a class="header-anchor" href="#iconfont-阿里字体图标" aria-hidden="true">#</a> iconfont 阿里字体图标</h2><ul><li><p>登陆 iconfont 官网，创建自己的项目，找到需要的图标加入购物车，然后添加到项目中</p></li><li><p>生成 unicode ,点击下载至本地，解压</p></li><li><p>将解压后的文件放入 <code>static/fonts/</code> 目录</p></li><li><p>修改文件路径<code>/static/fonts/iconfont.css</code></p><div class="language-css line-numbers-mode"><pre><code><span class="token atrule"><span class="token rule">@font-face</span></span> <span class="token punctuation">{</span>\n  <span class="token property">font-family</span><span class="token punctuation">:</span> <span class="token string">&#39;iconfont&#39;</span><span class="token punctuation">;</span> <span class="token comment">/* Project id 2482387 */</span>\n  <span class="token property">src</span><span class="token punctuation">:</span> <span class="token url"><span class="token function">url</span><span class="token punctuation">(</span><span class="token string url">&#39;~@/static/fonts/iconfont.woff2?t=1621379940889&#39;</span><span class="token punctuation">)</span></span> <span class="token function">format</span><span class="token punctuation">(</span><span class="token string">&#39;woff2&#39;</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token url"><span class="token function">url</span><span class="token punctuation">(</span><span class="token string url">&#39;~@/static/fonts/iconfont.woff?t=1621379940889&#39;</span><span class="token punctuation">)</span></span>\n      <span class="token function">format</span><span class="token punctuation">(</span><span class="token string">&#39;woff&#39;</span><span class="token punctuation">)</span><span class="token punctuation">,</span>\n    <span class="token url"><span class="token function">url</span><span class="token punctuation">(</span><span class="token string url">&#39;~@/static/fonts/iconfont.ttf?t=1621379940889&#39;</span><span class="token punctuation">)</span></span> <span class="token function">format</span><span class="token punctuation">(</span><span class="token string">&#39;truetype&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers-wrapper"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div></li><li><p>修改为本地引入方式</p></li><li><p>在 App.vue 中全局引入该文件 <code>@import &quot;./static/fonts/iconfont.css&quot;;</code></p></li><li></li></ul><h2 id="easycom-引入组件库"><a class="header-anchor" href="#easycom-引入组件库" aria-hidden="true">#</a> easycom 引入组件库</h2><p>此方案引入，支持 h5 与微信小程序中使用。</p><ul><li><a href="https://uniapp.dcloud.io/collocation/pages?id=easycom" target="_blank" rel="noopener noreferrer">easycom</a></li></ul><p>传统 vue 组件，需要安装、引用、注册，三个步骤后才能使用组件。 easycom 将其精简为一步。 只要组件安装在项目的 components 目录下，并符合 components/组件名称/组件名称.vue 目录结构。就可以不用引用、注册，直接在页面中使用。 如下：</p><ul><li>pages.json</li></ul><div class="language-json line-numbers-mode"><pre><code><span class="token punctuation">{</span>\n  <span class="token comment">// 加载组件库</span>\n  <span class="token property">&quot;easycom&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span>\n    <span class="token property">&quot;autoscan&quot;</span><span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span>\n    <span class="token property">&quot;custom&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span>\n      <span class="token property">&quot;nav-top-bar&quot;</span><span class="token operator">:</span> <span class="token string">&quot;@/components/bar/nav-top.vue&quot;</span><span class="token punctuation">,</span> <span class="token comment">// 匹配components目录内的vue文件</span>\n      <span class="token property">&quot;cell-nas&quot;</span><span class="token operator">:</span> <span class="token string">&quot;@/components/cell/nas.vue&quot;</span> <span class="token comment">// 匹配components目录内的vue文件</span>\n      <span class="token comment">// &quot;^uni-(.*)&quot;: &quot;@/components/uni-$1.vue&quot;, // 匹配components目录内的vue文件</span>\n      <span class="token comment">// &quot;^vue-file-(.*)&quot;: &quot;packageName/path/to/vue-file-$1.vue&quot; // 匹配node_modules内的vue文件</span>\n    <span class="token punctuation">}</span>\n  <span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers-wrapper"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><h2 id="传参"><a class="header-anchor" href="#传参" aria-hidden="true">#</a> 传参</h2><p>provide,inject【无法响应式实时更新，uni-app 框架中不建议使用】 $attrs,$listeners 这个在浏览器中可以，但是在 uni-app 框架中不支持 牵涉到多层传参或多页面传参建议使用【uni-app 框架建议使用 vuex】【浏览器端建议使用 Vue.prototype】</p>',12)];t.render=function(a,p,t,e,c,l){return n(),s("div",null,o)};export{p as __pageData,t as default};
